function solve(s: string, order: number[], k: number): number {
    const n = s.length;
    const total = n * (n + 1) / 2;
    const stars = new Set<number>();
    let invalid = total;

    for (let t = 0; t < n; t++) {
        const i = order[t];

        // Find left boundary
        let left = i;
        while (left > 0 && !stars.has(left - 1)) {
            left--;
        }

        // Find right boundary
        let right = i;
        while (right < n - 1 && !stars.has(right + 1)) {
            right++;
        }

        // Calculate original contribution
        const originalLength = right - left + 1;
        const original = originalLength * (originalLength + 1) / 2;

        // Calculate new contributions
        const newLeftLength = i - left;
        const newRightLength = right - i;
        const newLeft = newLeftLength * (newLeftLength + 1) / 2;
        const newRight = newRightLength * (newRightLength + 1) / 2;

        const delta = original - (newLeft + newRight);
        invalid -= delta;

        // Add current position to stars
        stars.add(i);

        // Check if valid
        const valid = total - invalid;
        if (valid >= k) {
            return t;
        }
    }

    return -1;
}
